"use client";
import Link from "next/link";
import { usePathname } from "next/navigation";

const navLinks = [
  { href: "/",        label: "Home"        },
  { href: "/channel", label: "Book Doctor" },
];

export default function Navbar() {
  const pathname = usePathname();

  return (
    <nav style={{
      position: "sticky", top: 0, zIndex: 50,
      backdropFilter: "blur(20px)", WebkitBackdropFilter: "blur(20px)",
      background: "rgba(2,8,24,0.92)",
      borderBottom: "1px solid rgba(56,189,248,0.18)",
      boxShadow: "0 1px 30px rgba(0,0,0,0.4)",
    }}>
      <div style={{
        width: "100%",
        padding: "0 32px",
        height: 72,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
      }}>

        {/* Logo — hard left */}
        <Link href="/" style={{ textDecoration: "none", display: "flex", alignItems: "center", gap: 10 }}>
          <img
            src="/logo.png"
            alt="Healix Pharm"
            style={{
              height: 40,
              width: 40,
              objectFit: "cover",
              borderRadius: 10,
              border: "1px solid rgba(56,189,248,0.15)",
            }}
          />
          <div>
            <div style={{
              fontFamily: "Syne, sans-serif", fontWeight: 800, fontSize: 17,
              background: "linear-gradient(135deg, #38bdf8, #818cf8)",
              WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
              backgroundClip: "text", lineHeight: 1,
            }}>Healix</div>
            <div style={{ color: "#334155", fontSize: 10, fontWeight: 500, letterSpacing: 1, marginTop: 2 }}>
              eCHANNELLING
            </div>
          </div>
        </Link>

        {/* Nav links — hard right */}
        <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
          {navLinks.map(link => {
            const active = link.href === "/"
              ? pathname === "/"
              : pathname.startsWith(link.href);
            return (
              <Link
                key={link.href}
                href={link.href}
                style={{
                  textDecoration: "none",
                  padding: "7px 18px",
                  borderRadius: 8,
                  fontSize: 14,
                  fontWeight: active ? 600 : 500,
                  color: active ? "#38bdf8" : "#94a3b8",
                  background: active ? "rgba(14,165,233,0.12)" : "transparent",
                  border: active ? "1px solid rgba(56,189,248,0.22)" : "1px solid transparent",
                  transition: "all 0.2s",
                }}
                onMouseEnter={e => {
                  if (!active) {
                    e.currentTarget.style.color = "#e2e8f0";
                    e.currentTarget.style.background = "rgba(255,255,255,0.04)";
                  }
                }}
                onMouseLeave={e => {
                  if (!active) {
                    e.currentTarget.style.color = "#94a3b8";
                    e.currentTarget.style.background = "transparent";
                  }
                }}
              >
                {link.label}
              </Link>
            );
          })}
        </div>

      </div>
    </nav>
  );
}